import{_ as a,o as i,c as e,a5 as n}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"概念：旁路同步（bypass synchronization）与旁路切换（bypass transfer）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：旁路同步（bypass synchronization）与旁路切换（bypass transfer）","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0023-single-phase-bypass-sync-transfer.html` 的源稿和补充资料，中文主讲。它只使用教学模型和教学参数，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据；学习记录中也不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。"},"headers":[],"relativePath":"content/power/concepts/control/single-phase-bypass-sync-transfer.md","filePath":"content/power/concepts/control/single-phase-bypass-sync-transfer.md","lastUpdated":null}'),l={name:"content/power/concepts/control/single-phase-bypass-sync-transfer.md"};function t(p,s,h,o,r,c){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="概念-旁路同步-bypass-synchronization-与旁路切换-bypass-transfer" tabindex="-1">概念：旁路同步（bypass synchronization）与旁路切换（bypass transfer） <a class="header-anchor" href="#概念-旁路同步-bypass-synchronization-与旁路切换-bypass-transfer" aria-label="Permalink to &quot;概念：旁路同步（bypass synchronization）与旁路切换（bypass transfer）&quot;">​</a></h1><p>本页是 <code>lessons/0023-single-phase-bypass-sync-transfer.html</code> 的源稿和补充资料，中文主讲。它只使用教学模型和教学参数，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据；学习记录中也不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>旁路同步（bypass synchronization）是判断 UPS 逆变输出与旁路电源是否足够接近。旁路切换（bypass transfer）是把负载从逆变器供电路径切到旁路路径，或从旁路切回逆变器路径。</p><p>本节只讲一个概念：电压幅值、频率、相位三项都进入同步窗口，并持续满足保持时间（hold time）后，才允许切换。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）可能在逆变器故障、过载、维修旁路或模式切换时使用旁路。如果逆变器与旁路不同步就切换，负载会看到突变电压，继电器或静态开关也可能承受冲击电流。</p><p>锁相环（phase-locked loop / PLL）提供旁路或电网相位信息，但 PLL 锁定不等于马上能切换。固件还要看均方根（root mean square / RMS）电压、频率差、相位误差（phase error）和保持时间。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>两个人交接一个正在转动的方向盘时，手的位置、速度和力度都要接近。只看其中一个条件不够。UPS 旁路切换也是类似：电压幅值像力度，频率像速度，相位像手的位置。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>voltage_ok   = abs(V_bypass - V_inv) / V_inv &lt;= voltage_window</span></span>
<span class="line"><span>frequency_ok = abs(f_bypass - f_inv) &lt;= frequency_window</span></span>
<span class="line"><span>phase_ok     = abs(theta_bypass - theta_inv) &lt;= phase_window</span></span>
<span class="line"><span>all_ok       = voltage_ok and frequency_ok and phase_ok</span></span>
<span class="line"><span>transfer_allowed = all_ok has lasted longer than hold_time</span></span></code></pre></div><p>默认教学参数：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>V_inv = 220 Vrms</span></span>
<span class="line"><span>voltage window = 10 %</span></span>
<span class="line"><span>frequency window = 0.20 Hz</span></span>
<span class="line"><span>phase window = 5 deg</span></span>
<span class="line"><span>hold time = 30 ms</span></span></code></pre></div><h2 id="_5-仿真观察" tabindex="-1">5. 仿真观察 <a class="header-anchor" href="#_5-仿真观察" aria-label="Permalink to &quot;5. 仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_bypass_sync_transfer.py</span></span></code></pre></div><p>脚本默认生成并尝试自动打开：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>simulations/results/single_phase_bypass_sync_transfer.png</span></span></code></pre></div><p>图中包含：</p><ul><li>逆变器 RMS 电压与旁路 RMS 电压。</li><li>频率差及频率窗口。</li><li>相位误差及相位窗口。</li><li>三个窗口是否同时满足，以及最终旁路切换许可。</li></ul><p>一个仿真任务：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_bypass_sync_transfer.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">phase</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">window</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">deg </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\bypass_sync_phase_2deg.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_bypass_sync_transfer.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sync-hold</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">time </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.060</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\bypass_sync_hold_60ms.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>观察相位窗口变窄、保持时间变长后，切换许可出现时间如何变化。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>真实 C 工程里，旁路切换常分散在几个模块中：</p><ul><li><code>pll.c</code>：给出旁路或电网相位。</li><li><code>rms.c</code>：计算逆变器与旁路 RMS 电压。</li><li><code>sync_check.c</code>：判断电压、频率、相位窗口和保持时间。</li><li><code>state_machine.c</code>：决定是否从逆变模式进入旁路模式。</li><li><code>protection.c</code>：在相位跳变、旁路异常、逆变器故障时撤销许可。</li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li>错误理解：PLL locked 就等于可以切旁路。<br> 正确理解：还要检查 RMS 电压、频率差、相位差和保持时间。</li><li>错误理解：相位刚好落入窗口的一瞬间就能切。<br> 正确理解：要保持一段时间，避免噪声或瞬时交叉造成误许可。</li><li>错误理解：旁路切换只是继电器动作。<br> 正确理解：动作前的软件许可、保护锁存、静态开关时序和状态机条件都很关键。</li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释旁路同步和旁路切换的区别。</li><li>能根据仿真图指出哪个条件最晚进入窗口。</li><li>能解释为什么需要保持时间。</li><li>能说明相位跳变后为什么要撤销切换许可。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>默认仿真中，三项同步窗口分别是什么？</li><li><code>All sync windows OK</code> 第一次变为 1 后，为什么 <code>Transfer allowed</code> 不是立刻变为 1？</li><li>200 ms 相位跳变后，哪条曲线先变化？状态机应该如何处理这个事件？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>single_phase_bypass_sync_transfer.py</code> 看到三项窗口都满足并保持 30 ms 后才允许切换。公司工程里旁路切换许可通常有哪些窗口阈值？</li><li>我在图中看到 200 ms 相位跳变后 <code>Transfer allowed</code> 立刻撤销。真实产品里相位异常后是否还会加入额外延时或故障锁存？</li><li>公司代码里旁路同步判断是在 PLL 模块、状态机模块，还是单独的同步检查模块中实现？</li></ul>`,35)])])}const y=a(l,[["render",t]]);export{k as __pageData,y as default};
